package com.kodewala.Array;

public class ArrayExample {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int number[] = new int[5];
		number[0] = 13;
		number[1] = 4;
		number[2] = 5;
		number[3] = 9;
		number[4] = 2;
		
		// // Access and print the array values (method 1: accessing specific indices)
		System.out.println("value at index 0 : "+number[0]);
		System.out.println("value at index 3 :"+number[3]);
	}

}
